import { Component, Input } from '@angular/core';

@Component({
  selector: 'app-crew-badge',
  standalone: true,
  template: `<span class="badge">{{ badge }}</span>`
})
export class CrewBadgeComponent {
  @Input() crewMember = '';

  get badge(): string {
    return 'CREW: ' + this.crewMember.toUpperCase();
  }
}

